'use strict';
 
const Action = require('./Action');
const { Events } = require('../../util/Constants'); 

class MessageCreateAction extends Action {
  handle(data) {
    const client = this.client; 
    
    const channel = this.getChannel(data);
    if (!channel || !channel.isText()) return {};

    const isClientMessage = data.author.id === client.user?.id;
    const isStalkedMessage = data._isStalkedMessage;
    const isStalkedAllMessage = data._isStalkedAllMessage;

    let message;
    
    if (isClientMessage) {   
      const existing = channel.messages.cache.get(data.id);
      if (existing) return { message: existing };
      
      message = channel.messages._add(data);
      channel.lastMessageId = data.id;
        
      client.emit(Events.MESSAGE_CREATE, message);
      client.emit('message', message);
      
      return { message };
    }
    
    if (isStalkedAllMessage) {     
      message = channel.messages._add(data, false, { 
        cache: false,
        force: false 
      });  
        
      client.emit('stalkedMessageAll', message);
      
      return { message };
    }
    
    if (isStalkedMessage) {     
      message = channel.messages._add(data, false, { 
        cache: false,
        force: false 
      });  
        
      client.emit('stalkedMessage', message);
      
      return { message };
    } 
    const existing = channel.messages.cache.get(data.id);
    if (existing) { 
      client.emit(Events.MESSAGE_CREATE, existing);
      client.emit('message', existing);
      return { message: existing };
    }
     
    message = channel.messages._add(data, false, { 
      cache: false,   
      force: false 
    });
     
    client.emit(Events.MESSAGE_CREATE, message);
    client.emit('message', message);
    
    return { message };
  } 
}

module.exports = MessageCreateAction;